return [{ json: {
  test_title: 'Onboarding Flow Usability Test — July 2026',
  test_date: '2026-07-10',
  prototype_version: 'v2.3',
  tasks: [
    {
      task_id: 'T1',
      task: 'Create a new project called "Q3 Launch" with a start date of August 1 and add 3 tasks',
      success_rate_pct: 60,
      avg_time_seconds: 142,
      notes: [
        { participant: 'P1', outcome: 'success', note: 'Struggled to find where to add a start date. Clicked into Settings first before finding the Date field.' },
        { participant: 'P2', outcome: 'success', note: 'Completed smoothly. No hesitation.' },
        { participant: 'P3', outcome: 'failure', note: 'Could not find the Add Task button. Kept looking in the sidebar.' },
        { participant: 'P4', outcome: 'failure', note: 'Created the project but could not figure out how to add tasks — expected a modal not inline editing.' },
        { participant: 'P5', outcome: 'success', note: 'Slow but completed. Said: "This isn\'t where I expected it to be, but I found it."' }
      ]
    },
    {
      task_id: 'T2',
      task: 'Assign the first task to a team member and set a due date of August 15',
      success_rate_pct: 80,
      avg_time_seconds: 68,
      notes: [
        { participant: 'P1', outcome: 'success', note: 'Easy. The assignee dropdown was clear.' },
        { participant: 'P2', outcome: 'success', note: 'No issues.' },
        { participant: 'P3', outcome: 'success', note: 'Found it quickly once in the task.' },
        { participant: 'P4', outcome: 'failure', note: 'Due date field was not visible because the task row was collapsed. Did not know to expand it.' },
        { participant: 'P5', outcome: 'success', note: 'Completed easily.' }
      ]
    },
    {
      task_id: 'T3',
      task: 'Set a task as recurring — repeat every Monday',
      success_rate_pct: 40,
      avg_time_seconds: 198,
      notes: [
        { participant: 'P1', outcome: 'failure', note: 'Never found the recurrence option. Said: "I assume this doesn\'t exist or it\'s buried somewhere."' },
        { participant: 'P2', outcome: 'success', note: 'Found it in the task detail panel eventually. Took about 2 minutes.' },
        { participant: 'P3', outcome: 'failure', note: 'Looked in the task context menu, in settings, and gave up after 3 minutes.' },
        { participant: 'P4', outcome: 'success', note: 'Found the recurrence option in the date picker — said it was not obvious.' },
        { participant: 'P5', outcome: 'failure', note: 'Did not complete. "I would just Google this."' }
      ]
    }
  ]
} }];

const d = $input.first().json;
const tasksText = d.tasks.map(t => {
  const noteLines = t.notes.map(n => `    [${n.participant}|${n.outcome}] ${n.note}`).join('\n');
  return `Task ${t.task_id}: "${t.task}"\n  Success: ${t.success_rate_pct}% | Avg time: ${t.avg_time_seconds}s\n  Notes:\n${noteLines}`;
}).join('\n\n');
const system = `You are a UX researcher summarising usability test findings. You extract patterns across participants, identify systemic issues vs one-off problems, and provide specific, actionable design recommendations. Return ONLY valid JSON.`;
const user = `Summarise this usability test: "${d.test_title}" (${d.test_date}, prototype ${d.prototype_version})

${tasksText}

Return JSON:
{
  "overall_usability_rating": "high|medium|low",
  "task_summaries": [
    { "task_id": "string", "task": "string", "success_rate_pct": 60, "avg_time_seconds": 142, "severity": "critical|major|minor", "primary_issue": "string", "key_quotes": ["string"] }
  ],
  "systemic_issues": [{ "issue": "string", "affected_tasks": ["T1"], "severity": "critical|major|minor", "root_cause": "string" }],
  "positive_findings": ["string"],
  "design_recommendations": [{ "recommendation": "string", "priority": "high|medium|low", "affected_tasks": ["string"], "rationale": "string" }],
  "executive_summary": "string — 3-4 sentence summary suitable for stakeholders"
}`;
return [{ json: { data: d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Summary Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.task_summaries || !Array.isArray(parsed.task_summaries)) return [{ json: { _error: true, reason: 'Missing task_summaries' } }];
return [{ json: { _error: false, summary: parsed, meta: { test_title: upstream.data.test_title, test_date: upstream.data.test_date, generated_at: new Date().toISOString() } } }];
